input.newString:
export function formatTitle(value, mode = 'plain') {
  if (mode === 'upper') return value.toUpperCase()
  if (mode === 'lower') return value.toLowerCase()
  if (mode === 'title') {
    return value.toLowerCase().split(' ').map((word, i) => {
      return i === 0
        ? word.charAt(0).toUpperCase() + word.slice(1)
        : word.charAt(0).toUpperCase() + word.slice(1)
    }).join(' ')
  }
  return value
}

